function createCounter(initialValue = 0) {
  let counter = initialValue;
  return {
    increment() {
      counter++;
      return counter;
    },
    decrement() {
      counter--;
      return counter;
    },
    getValue() {
      return counter;
    }
  };
}

const myCounter = createCounter(5);
console.log(myCounter.increment()); // Output: 6
console.log(myCounter.increment()); // Output: 7
console.log(myCounter.decrement()); // Output: 6
console.log(myCounter.getValue());  // Output: 6

