class NetworkError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "NetworkError";
  }
}

class ValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "ValidationError";
  }
}

function fetchData(url: string): Promise<string> {
  return new Promise((resolve, reject) => {
    // Simulate network request
    if (!url.startsWith("http")) {
      reject(new ValidationError("Invalid URL format"));
    } else {
      // Simulate network failure
      reject(new NetworkError("Failed to connect"));
    }
  });
}

async function getData() {
  try {
    const data = await fetchData("invalid-url");
    console.log(data);
  } catch (error) {
    if (error instanceof ValidationError) {
      console.error("Validation issue:", error.message);
    } else if (error instanceof NetworkError) {
      console.error("Network issue:", error.message);
    } else {
      console.error("Unexpected error:", error);
    }
  }
}

getData();

type Result<T, E> =
  | { success: true; value: T }
  | { success: false; error: E };

function parseJson(input: string): Result<object, string> {
  try {
    const data = JSON.parse(input);
    return { success: true, value: data };
  } catch (e) {
    return { success: false, error: "Invalid JSON format" };
  }
}

const result = parseJson("{\"name\":\"John\"}");

if (result.success) {
  console.log("Parsed data:", result.value);
} else {
  console.error("Error:", result.error);
}

function isNetworkError(error: unknown): error is NetworkError {
  return error instanceof NetworkError;
}

try {
  throw new NetworkError("Network is down");
} catch (error) {
  if (isNetworkError(error)) {
    console.log("Handled a network error:", error.message);
  } else {
    console.log("Generic error:", error);
  }
}

from typing import List, Dict, Optional

# List of integers
def sum_numbers(numbers: List[int]) -> int:
    return sum(numbers)

# Dictionary with string keys and integer values
def count_occurrences(items: List[str]) -> Dict[str, int]:
    counts = {}
    for item in items:
        counts[item] = counts.get(item, 0) + 1
    return counts

# Optional means the parameter can be None or the stated type
def get_length(s: Optional[str]) -> int:
    if s is None:
        return 0
    return len(s)

from typing import List, Optional

def average(scores: List[float]) -> Optional[float]:
    if not scores:
        return None
    return sum(scores) / len(scores)

result = average([88.5, 92.0, 79.5])
if result is not None:
    print(f"Average score: {result:.2f}")
else:
    print("No scores available.")

